import java.util.Scanner;

public class BufferOverflowFixed {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length before copying to buffer
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum length. Please enter a shorter name.");
            return;
        }

        // Use a dynamic array instead of fixed size array to avoid buffer overflow
        char[] buffer = new char[name.length()];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
